    const handleSectionToggle = useCallback((sectionIndex: number) => {
      // Find current collapse state from the section
      const section = sections.find(s => s.sectionIndex === sectionIndex);
      const currentCollapsed = section?.group?.collapsed ?? false;
      const newCollapsed = !currentCollapsed;
      // Notify parent to update config - the config is the source of truth
