  DashboardPanelContainerRef,
  DashboardPanelContainerProps
>(
  (
    {
      dashboard,
      dashboardId,
      initialTimeSpan,
      initialFilterExpression,
      initialLoading,
      onChartSelection,
      showSectionEditControls = false,
      onSectionRename,
      onSectionDelete,
      onSectionCollapseChange,
      children,
    },
    ref
